import xml.etree.ElementTree as ET


def is_closed_contour(contour):
    """
    Проверяет, является ли контур замкнутым (многоугольником).
    Контур считается замкнутым, если первая и последняя координаты совпадают.
    """
    spatial_elements = contour.findall('.//spatial_element')
    for spatial in spatial_elements:
        ordinates = spatial.findall('.//ordinate')
        if len(ordinates) < 3:  # У линии должно быть минимум 2 точки, но для многоугольника нужно минимум 3
            return False
        first = ordinates[0]
        last = ordinates[-1]
        if (first.get('x') != last.get('x') or first.get('y') != last.get('y')):
            return False
    return True


def remove_linear_contours(xml_content):
    """
    Удаляет из XML все контуры, которые являются линиями (незамкнутыми).
    """
    root = ET.fromstring(xml_content)

    # Удаление незамкнутых контуров в object_parts
    object_parts = root.findall('.//object_parts//object_part')
    for part in object_parts:
        contours = part.findall('.//contours//contour')
        for contour in contours:
            if not is_closed_contour(contour):
                part.remove(contour)

    # Удаление незамкнутых контуров в contours_location
    contours_location = root.find('.//contours_location')
    if contours_location is not None:
        contours = contours_location.findall('.//contour')
        for contour in contours:
            if not is_closed_contour(contour):
                contours_location.remove(contour)

    # Удаление границ (borders), которые ссылаются на удалённые контуры
    borders = root.find('.//borders')
    if borders is not None:
        # Собираем номера контуров, которые остались в contours_location
        remaining_contours = set()
        for contour in contours_location.findall('.//contour'):
            number_pp = contour.get('number_pp')
            if number_pp:
                remaining_contours.add(number_pp)

        # Удаляем границы, которые ссылаются на отсутствующие контуры
        for border in borders.findall('.//border'):
            by_definition = border.find('.//by_definition')
            if by_definition is not None:
                nmb_contour = by_definition.find('nmb_contour')
                if nmb_contour is not None and nmb_contour.text not in remaining_contours:
                    borders.remove(border)

    # Возвращаем изменённый XML в виде строки
    return ET.tostring(root, encoding='unicode', method='xml')


